import React from 'react';

const statusColors = {
  pending: { bg: '#fff3cd', color: '#856404' },
  preparing: { bg: '#cce5ff', color: '#004085' },
  ready: { bg: '#d4edda', color: '#155724' },
  delivered: { bg: '#e2e3e5', color: '#383d41' },
};

const styles = {
  card: {
    background: '#fff',
    borderRadius: 12,
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
    padding: 16,
    marginBottom: 12,
  },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 },
  orderId: { fontWeight: 700, fontSize: 16 },
  badge: (status) => ({
    padding: '3px 10px',
    borderRadius: 20,
    fontSize: 12,
    fontWeight: 600,
    background: statusColors[status]?.bg || '#eee',
    color: statusColors[status]?.color || '#333',
  }),
  meta: { fontSize: 12, color: '#888', marginBottom: 10 },
  items: { borderTop: '1px solid #f0f0f0', paddingTop: 8, marginBottom: 10 },
  item: { fontSize: 13, color: '#333', marginBottom: 4 },
  special: { fontSize: 12, color: '#888', fontStyle: 'italic', marginBottom: 10 },
  btn: (color) => ({
    padding: '8px 20px',
    borderRadius: 8,
    border: 'none',
    background: color,
    color: '#fff',
    fontWeight: 600,
    fontSize: 13,
    cursor: 'pointer',
    marginRight: 8,
  }),
};

export default function OrderCard({ order, onAction, actionLabel, actionColor = '#222' }) {
  const time = new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  return (
    <div style={styles.card}>
      <div style={styles.header}>
        <span style={styles.orderId}>Order #{order.id}</span>
        <span style={styles.badge(order.status)}>{order.status?.toUpperCase()}</span>
      </div>
      <div style={styles.meta}>
        Table {order.table_number} &bull; {time}
      </div>
      <div style={styles.items}>
        {(order.items || []).map((item, i) => (
          <div key={i} style={styles.item}>
            {item.quantity}x {item.name}
          </div>
        ))}
      </div>
      {order.special_requests && (
        <div style={styles.special}>Note: {order.special_requests}</div>
      )}
      {onAction && actionLabel && (
        <button style={styles.btn(actionColor)} onClick={() => onAction(order)}>
          {actionLabel}
        </button>
      )}
    </div>
  );
}
