import React from 'react';

const statusStyle = {
  free: { background: '#d4edda', color: '#155724', border: '2px solid #c3e6cb' },
  occupied: { background: '#f8d7da', color: '#721c24', border: '2px solid #f5c6cb' },
  awaiting_delivery: { background: '#fff3cd', color: '#856404', border: '2px solid #ffeeba' },
};

const styles = {
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))',
    gap: 10,
  },
  cell: (status) => ({
    ...statusStyle[status] || statusStyle.free,
    borderRadius: 10,
    padding: '10px 6px',
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'opacity 0.2s',
  }),
  num: { fontWeight: 700, fontSize: 18 },
  label: { fontSize: 10, fontWeight: 600, marginTop: 2 },
};

const statusLabel = {
  free: 'FREE',
  occupied: 'OCCUPIED',
  awaiting_delivery: 'READY',
};

export default function TableMap({ tables, onTableClick }) {
  if (!tables || tables.length === 0) {
    return <div style={{ color: '#888', padding: 20 }}>No tables available</div>;
  }

  return (
    <div style={styles.grid}>
      {tables.map((table) => (
        <div
          key={table.id}
          style={styles.cell(table.status)}
          onClick={() => onTableClick && onTableClick(table)}
        >
          <div style={styles.num}>{table.table_number}</div>
          <div style={styles.label}>{statusLabel[table.status] || table.status}</div>
        </div>
      ))}
    </div>
  );
}
