import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getOrder } from '../api/orders';
import { getInvoice, payInvoice } from '../api/billing';
import { useWebSocket } from '../hooks/useWebSocket';
import StatusBar from '../components/StatusBar';

const styles = {
  page: { minHeight: '100vh', background: '#f5f5f5', paddingBottom: 80 },
  header: {
    background: '#fff',
    padding: '14px 20px',
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
  },
  backBtn: { background: 'none', border: 'none', fontSize: 22, cursor: 'pointer', padding: 0 },
  title: { fontWeight: 700, fontSize: 18 },
  content: { padding: 20, maxWidth: 500, margin: '0 auto' },
  card: {
    background: '#fff',
    borderRadius: 12,
    padding: 16,
    marginBottom: 16,
    boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
  },
  sectionTitle: { fontWeight: 600, fontSize: 13, color: '#555', marginBottom: 12 },
  item: { display: 'flex', justifyContent: 'space-between', fontSize: 14, marginBottom: 6 },
  total: { fontWeight: 700, fontSize: 16, textAlign: 'right', borderTop: '1px solid #f0f0f0', paddingTop: 8, marginTop: 8 },
  empty: { textAlign: 'center', color: '#aaa', padding: 40, fontSize: 15 },
  error: { background: '#fde8e8', color: '#e74c3c', borderRadius: 8, padding: '10px 14px', fontSize: 13, marginBottom: 12 },
  payBtn: (disabled) => ({
    width: '100%',
    padding: 12,
    borderRadius: 8,
    border: 'none',
    background: disabled ? '#ccc' : '#27ae60',
    color: '#fff',
    fontWeight: 700,
    fontSize: 15,
    cursor: disabled ? 'not-allowed' : 'pointer',
    marginTop: 8,
  }),
  nav: {
    position: 'fixed', bottom: 0, left: 0, right: 0,
    background: '#fff', borderTop: '1px solid #eee',
    display: 'flex', zIndex: 100,
  },
  navBtn: (active) => ({
    flex: 1, padding: '12px 0', border: 'none', background: 'none',
    fontWeight: active ? 700 : 500, fontSize: 12,
    color: active ? '#222' : '#999', cursor: 'pointer',
    borderTop: active ? '2px solid #222' : '2px solid transparent',
  }),
};

export default function OrderTracking() {
  const navigate = useNavigate();
  const [orderId, setOrderId] = useState(null);
  const [order, setOrder] = useState(null);
  const [invoice, setInvoice] = useState(null);
  const [loading, setLoading] = useState(true);
  const [payLoading, setPayLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const id = localStorage.getItem('current_order_id');
    if (id) {
      setOrderId(Number(id));
    } else {
      setLoading(false);
    }
  }, []);

  const fetchOrder = useCallback(async (id) => {
    try {
      const res = await getOrder(id);
      setOrder(res.data);
      if (res.data.status === 'delivered') {
        try {
          const inv = await getInvoice(id);
          setInvoice(inv.data);
        } catch (_) {}
      }
    } catch (err) {
      setError('Could not load order');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (orderId) fetchOrder(orderId);
  }, [orderId, fetchOrder]);

  const handleWsMessage = useCallback((data) => {
    if (data.type === 'order_status_update') {
      setOrder((prev) => prev ? { ...prev, status: data.status, updated_at: data.updated_at } : prev);
      if (data.status === 'delivered' && orderId) {
        getInvoice(orderId).then((res) => setInvoice(res.data)).catch(() => {});
      }
    }
  }, [orderId]);

  useWebSocket(orderId ? `/ws/orders/${orderId}/` : null, handleWsMessage);

  const handlePay = async () => {
    if (!invoice) return;
    setPayLoading(true);
    setError('');
    try {
      const res = await payInvoice(orderId);
      setInvoice((prev) => ({ ...prev, ...res.data }));
      localStorage.removeItem('current_order_id');
      localStorage.removeItem('table_id');
      localStorage.removeItem('table_number');
    } catch (err) {
      setError(err.response?.data?.detail || 'Payment failed');
    } finally {
      setPayLoading(false);
    }
  };

  const totalPrice = order?.items?.reduce((s, i) => s + Number(i.price_at_order) * i.quantity, 0) || 0;

  if (loading) return <div style={{ padding: 40, textAlign: 'center' }}>Loading...</div>;

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <button style={styles.backBtn} onClick={() => navigate('/menu')}>←</button>
        <div style={styles.title}>ORDER TRACKING</div>
      </div>

      <div style={styles.content}>
        {error && <div style={styles.error}>{error}</div>}

        {!order ? (
          <div style={styles.empty}>No active order. Place an order first.</div>
        ) : (
          <>
            <div style={styles.card}>
              <div style={styles.sectionTitle}>ORDER #{order.id} STATUS</div>
              <StatusBar status={order.status} />
            </div>

            <div style={styles.card}>
              <div style={styles.sectionTitle}>ORDER ITEMS</div>
              {(order.items || []).map((item, i) => (
                <div key={i} style={styles.item}>
                  <span>{item.quantity}x {item.name}</span>
                  <span>${(Number(item.price_at_order) * item.quantity).toFixed(2)}</span>
                </div>
              ))}
              <div style={styles.total}>Total: ${totalPrice.toFixed(2)}</div>
            </div>

            {invoice && (
              <div style={styles.card}>
                <div style={styles.sectionTitle}>INVOICE</div>
                <div style={styles.item}>
                  <span>Payment status</span>
                  <span style={{ fontWeight: 600, color: invoice.status === 'paid' ? '#27ae60' : '#e67e22' }}>
                    {invoice.status?.toUpperCase()}
                  </span>
                </div>
                <div style={styles.total}>Total: ${Number(invoice.total_amount).toFixed(2)}</div>
                {invoice.status !== 'paid' && (
                  <button style={styles.payBtn(payLoading)} onClick={handlePay} disabled={payLoading}>
                    {payLoading ? 'Processing...' : 'PAY NOW'}
                  </button>
                )}
                {invoice.status === 'paid' && (
                  <div style={{ color: '#27ae60', fontWeight: 600, textAlign: 'center', marginTop: 10 }}>
                    Payment successful! Thank you.
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>

      <div style={styles.nav}>
        <button style={styles.navBtn(false)} onClick={() => navigate('/menu')}>MENU</button>
        <button style={styles.navBtn(false)} onClick={() => navigate('/order')}>MY ORDER</button>
        <button style={styles.navBtn(true)}>TRACK</button>
        <button style={styles.navBtn(false)} onClick={() => navigate('/track')}>BILL</button>
      </div>
    </div>
  );
}
