import React, { useEffect, useState, useCallback } from 'react';
import { getMenu, createMenuItem, updateMenuItem, deleteMenuItem } from '../api/menu';
import {
  createPricingRule,
  createStaff,
  deletePricingRule,
  getAnalytics,
  getPricingRules,
  getSimulationLive,
  getSimulationStatus,
  resetSimulation,
  startSimulation,
  stopSimulation,
} from '../api/manager';
import { RevenueChart, TopDishesChart, PeakHoursChart } from '../components/AnalyticsChart';
import { useWebSocket } from '../hooks/useWebSocket';

const TABS = ['Menu', 'Staff', 'Pricing', 'Analytics', 'Simulation'];

const styles = {
  page: { minHeight: '100vh', background: '#f5f5f5' },
  header: {
    background: '#fff', padding: '14px 24px',
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
  },
  title: { fontWeight: 800, fontSize: 18, letterSpacing: 1 },
  tabs: { display: 'flex', background: '#fff', borderBottom: '2px solid #f0f0f0', paddingLeft: 24 },
  tab: (active) => ({
    padding: '12px 20px', border: 'none', background: 'none',
    fontWeight: active ? 700 : 500, fontSize: 14,
    color: active ? '#222' : '#888', cursor: 'pointer',
    borderBottom: active ? '2px solid #222' : '2px solid transparent',
    marginBottom: -2,
  }),
  content: { padding: 24, maxWidth: 900, margin: '0 auto' },
  card: { background: '#fff', borderRadius: 12, padding: 20, marginBottom: 20, boxShadow: '0 1px 4px rgba(0,0,0,0.06)' },
  sectionTitle: { fontWeight: 700, fontSize: 14, marginBottom: 14, color: '#333' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', fontSize: 12, fontWeight: 600, color: '#888', padding: '6px 8px', borderBottom: '1px solid #f0f0f0' },
  td: { padding: '10px 8px', fontSize: 13, borderBottom: '1px solid #f8f8f8' },
  input: {
    padding: '8px 12px', borderRadius: 8, border: '1.5px solid #e0e0e0',
    fontSize: 13, outline: 'none', width: '100%', boxSizing: 'border-box', marginBottom: 8,
  },
  row: { display: 'flex', gap: 10, flexWrap: 'wrap', marginBottom: 8 },
  btn: (color = '#222', disabled = false) => ({
    padding: '8px 18px', borderRadius: 8, border: 'none',
    background: disabled ? '#ccc' : color, color: '#fff',
    fontWeight: 600, fontSize: 13, cursor: disabled ? 'not-allowed' : 'pointer',
  }),
  deleteBtn: {
    padding: '4px 10px', borderRadius: 6, border: '1px solid #e74c3c',
    background: '#fff', color: '#e74c3c', fontSize: 12, cursor: 'pointer', marginLeft: 6,
  },
  editBtn: {
    padding: '4px 10px', borderRadius: 6, border: '1px solid #4f46e5',
    background: '#fff', color: '#4f46e5', fontSize: 12, cursor: 'pointer',
  },
  error: { background: '#fde8e8', color: '#e74c3c', borderRadius: 8, padding: '8px 12px', fontSize: 13, marginBottom: 12 },
  success: { background: '#d4edda', color: '#155724', borderRadius: 8, padding: '8px 12px', fontSize: 13, marginBottom: 12 },
  periodRow: { display: 'flex', gap: 8, marginBottom: 20 },
  periodBtn: (active) => ({
    padding: '6px 16px', borderRadius: 20, border: '1.5px solid',
    borderColor: active ? '#222' : '#ddd', background: active ? '#222' : '#fff',
    color: active ? '#fff' : '#555', fontWeight: 600, fontSize: 12, cursor: 'pointer',
  }),
};

function MenuTab() {
  const [items, setItems] = useState([]);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ name: '', description: '', price: '', category: '', image_url: '', available: true });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const fetchItems = useCallback(() => {
    getMenu().then((r) => {
      // Handle both flat array and DRF paginated {results: [...]} responses
      const data = r.data;
      setItems(Array.isArray(data) ? data : (data.results || []));
    }).catch(() => {});
  }, []);

  useEffect(() => { fetchItems(); }, [fetchItems]);

  const set = (f) => (e) => setForm((p) => ({ ...p, [f]: e.target.type === 'checkbox' ? e.target.checked : e.target.value }));

  const handleSave = async () => {
    setError(''); setSuccess('');
    if (!form.name || !form.price || !form.category) {
      setError('Name, price and category are required');
      return;
    }
    setLoading(true);
    try {
      if (editing) {
        await updateMenuItem(editing.id, form);
        setSuccess('Item updated');
      } else {
        await createMenuItem(form);
        setSuccess('Item created');
      }
      setEditing(null);
      setForm({ name: '', description: '', price: '', category: '', image_url: '', available: true });
      fetchItems();
    } catch (err) {
      setError(err.response?.data?.detail || 'Save failed');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setEditing(item);
    setForm({ name: item.name, description: item.description || '', price: item.price, category: item.category, image_url: item.image_url || '', available: item.available });
    setError(''); setSuccess('');
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this item?')) return;
    try {
      await deleteMenuItem(id);
      fetchItems();
    } catch (_) {}
  };

  return (
    <div>
      <div style={styles.card}>
        <div style={styles.sectionTitle}>{editing ? 'Edit Item' : 'Add Item'}</div>
        {error && <div style={styles.error}>{error}</div>}
        {success && <div style={styles.success}>{success}</div>}
        <div style={styles.row}>
          <div style={{ flex: 2, minWidth: 150 }}>
            <input style={styles.input} placeholder="Name *" value={form.name} onChange={set('name')} disabled={loading} />
          </div>
          <div style={{ flex: 1, minWidth: 80 }}>
            <input style={styles.input} placeholder="Price *" type="number" step="0.01" value={form.price} onChange={set('price')} disabled={loading} />
          </div>
          <div style={{ flex: 1, minWidth: 100 }}>
            <input style={styles.input} placeholder="Category *" value={form.category} onChange={set('category')} disabled={loading} />
          </div>
        </div>
        <input style={styles.input} placeholder="Description" value={form.description} onChange={set('description')} disabled={loading} />
        <input style={styles.input} placeholder="Image URL" value={form.image_url} onChange={set('image_url')} disabled={loading} />
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
          <input type="checkbox" checked={form.available} onChange={set('available')} id="avail" />
          <label htmlFor="avail" style={{ fontSize: 13 }}>Available</label>
        </div>
        <div style={styles.row}>
          <button style={styles.btn('#4f46e5', loading)} onClick={handleSave} disabled={loading}>
            {loading ? 'Saving...' : editing ? 'UPDATE' : 'ADD ITEM'}
          </button>
          {editing && (
            <button style={styles.btn('#888')} onClick={() => { setEditing(null); setForm({ name: '', description: '', price: '', category: '', image_url: '', available: true }); }}>
              CANCEL
            </button>
          )}
        </div>
      </div>

      <div style={styles.card}>
        <div style={styles.sectionTitle}>Menu Items ({items.length})</div>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Category</th>
              <th style={styles.th}>Price</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {items.map((item) => (
              <tr key={item.id}>
                <td style={styles.td}>{item.name}</td>
                <td style={styles.td}>{item.category}</td>
                <td style={styles.td}>${Number(item.price).toFixed(2)}</td>
                <td style={styles.td}>
                  <span style={{ color: item.available ? '#27ae60' : '#e74c3c', fontWeight: 600, fontSize: 12 }}>
                    {item.available ? 'Available' : 'Unavailable'}
                  </span>
                </td>
                <td style={styles.td}>
                  <button style={styles.editBtn} onClick={() => handleEdit(item)}>Edit</button>
                  <button style={styles.deleteBtn} onClick={() => handleDelete(item.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function StaffTab() {
  const [form, setForm] = useState({ username: '', email: '', password: '', role: 'waiter' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const set = (f) => (e) => setForm((p) => ({ ...p, [f]: e.target.value }));

  const handleCreate = async () => {
    setError(''); setSuccess('');
    if (!form.username || !form.email || !form.password) {
      setError('All fields required');
      return;
    }
    setLoading(true);
    try {
      await createStaff(form);
      setSuccess(`Staff member "${form.username}" created successfully`);
      setForm({ username: '', email: '', password: '', role: 'waiter' });
    } catch (err) {
      setError(err.response?.data?.detail || JSON.stringify(err.response?.data) || 'Failed to create staff');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.card}>
      <div style={styles.sectionTitle}>Create Staff Account</div>
      {error && <div style={styles.error}>{error}</div>}
      {success && <div style={styles.success}>{success}</div>}
      <input style={styles.input} placeholder="Username" value={form.username} onChange={set('username')} disabled={loading} />
      <input style={styles.input} placeholder="Email" type="email" value={form.email} onChange={set('email')} disabled={loading} />
      <input style={styles.input} placeholder="Password" type="password" value={form.password} onChange={set('password')} disabled={loading} />
      <div style={{ marginBottom: 12 }}>
        <select
          style={{ ...styles.input, marginBottom: 0 }}
          value={form.role}
          onChange={set('role')}
          disabled={loading}
        >
          <option value="waiter">Waiter</option>
          <option value="kitchen_staff">Kitchen Staff</option>
          <option value="manager">Manager</option>
        </select>
      </div>
      <button style={styles.btn('#4f46e5', loading)} onClick={handleCreate} disabled={loading}>
        {loading ? 'Creating...' : 'CREATE STAFF'}
      </button>
    </div>
  );
}

function PricingTab() {
  const [rules, setRules] = useState([]);
  const [form, setForm] = useState({ demand_threshold: '', multiplier: '', time_start: '', time_end: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const fetchRules = useCallback(() => {
    getPricingRules().then((r) => setRules(r.data)).catch(() => setRules([]));
  }, []);

  useEffect(() => { fetchRules(); }, [fetchRules]);

  const set = (f) => (e) => setForm((p) => ({ ...p, [f]: e.target.value }));

  const handleCreate = async () => {
    setError(''); setSuccess('');
    if (!form.demand_threshold || !form.multiplier) {
      setError('Demand threshold and multiplier are required');
      return;
    }
    setLoading(true);
    try {
      await createPricingRule(form);
      setSuccess('Pricing rule created');
      setForm({ demand_threshold: '', multiplier: '', time_start: '', time_end: '' });
      fetchRules();
    } catch (err) {
      setError(err.response?.data?.detail || 'Failed to create rule');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      await deletePricingRule(id);
      fetchRules();
    } catch (_) {}
  };

  return (
    <div>
      <div style={styles.card}>
        <div style={styles.sectionTitle}>Add Pricing Rule</div>
        {error && <div style={styles.error}>{error}</div>}
        {success && <div style={styles.success}>{success}</div>}
        <div style={styles.row}>
          <div style={{ flex: 1 }}>
            <input style={styles.input} placeholder="Demand threshold (orders/hr)" type="number" value={form.demand_threshold} onChange={set('demand_threshold')} />
          </div>
          <div style={{ flex: 1 }}>
            <input style={styles.input} placeholder="Multiplier (e.g. 1.2)" type="number" step="0.01" value={form.multiplier} onChange={set('multiplier')} />
          </div>
        </div>
        <div style={styles.row}>
          <div style={{ flex: 1 }}>
            <input style={styles.input} placeholder="Time start (HH:MM)" value={form.time_start} onChange={set('time_start')} />
          </div>
          <div style={{ flex: 1 }}>
            <input style={styles.input} placeholder="Time end (HH:MM)" value={form.time_end} onChange={set('time_end')} />
          </div>
        </div>
        <button style={styles.btn('#4f46e5', loading)} onClick={handleCreate} disabled={loading}>
          {loading ? 'Saving...' : 'ADD RULE'}
        </button>
      </div>

      <div style={styles.card}>
        <div style={styles.sectionTitle}>Active Rules</div>
        {rules.length === 0 ? (
          <div style={{ color: '#aaa', fontSize: 13 }}>No pricing rules configured</div>
        ) : (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Demand Threshold</th>
                <th style={styles.th}>Multiplier</th>
                <th style={styles.th}>Time Window</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {rules.map((rule) => (
                <tr key={rule.id}>
                  <td style={styles.td}>{rule.demand_threshold} orders/hr</td>
                  <td style={styles.td}>x{rule.multiplier}</td>
                  <td style={styles.td}>{rule.time_start && rule.time_end ? `${rule.time_start} – ${rule.time_end}` : 'All day'}</td>
                  <td style={styles.td}>
                    <button style={styles.deleteBtn} onClick={() => handleDelete(rule.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

function AnalyticsTab() {
  const [period, setPeriod] = useState('day');
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchAnalytics = useCallback((p) => {
    setLoading(true);
    getAnalytics(p)
      .then((r) => setData(r.data))
      .catch(() => setData(null))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { fetchAnalytics(period); }, [period, fetchAnalytics]);

  return (
    <div>
      <div style={styles.periodRow}>
        {['day', 'week', 'month'].map((p) => (
          <button key={p} style={styles.periodBtn(period === p)} onClick={() => setPeriod(p)}>
            {p.charAt(0).toUpperCase() + p.slice(1)}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ padding: 40, textAlign: 'center', color: '#888' }}>Loading analytics...</div>
      ) : !data ? (
        <div style={{ padding: 40, textAlign: 'center', color: '#aaa' }}>No analytics data available</div>
      ) : (
        <div style={styles.card}>
          {data.revenue && (
            <div style={{ marginBottom: 12 }}>
              <div style={{ fontWeight: 700, fontSize: 22 }}>${Number(data.revenue.total || 0).toFixed(2)}</div>
              <div style={{ fontSize: 12, color: '#888' }}>Total Revenue ({period})</div>
            </div>
          )}
          {data.revenue?.by_day && <RevenueChart data={data.revenue.by_day} />}
          {data.top_dishes && <TopDishesChart data={data.top_dishes} />}
          {data.peak_hours && <PeakHoursChart data={data.peak_hours} />}
          {data.table_turnover && (
            <div style={{ fontSize: 13, color: '#555' }}>
              Avg table turnover: <strong>{Math.round(data.table_turnover.avg_minutes_per_table)} min</strong>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

const simStyles = {
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: 14, marginBottom: 20 },
  liveCard: (color = '#f0f0f0') => ({
    background: color, borderRadius: 12, padding: '14px 16px',
    boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
  }),
  badge: (trend) => ({
    display: 'inline-block', padding: '2px 8px', borderRadius: 12, fontSize: 11, fontWeight: 700,
    background: trend > 0 ? '#d4edda' : trend < 0 ? '#fde8e8' : '#f0f0f0',
    color: trend > 0 ? '#155724' : trend < 0 ? '#721c24' : '#555',
    marginLeft: 6,
  }),
  cmdBox: {
    background: '#1e1e2e', color: '#a6e3a1', borderRadius: 8, padding: '12px 16px',
    fontFamily: 'monospace', fontSize: 12, lineHeight: 1.7, marginBottom: 14,
    overflowX: 'auto',
  },
  statRow: { display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' },
  stat: { background: '#fff', borderRadius: 10, padding: '10px 18px', flex: 1, minWidth: 100, boxShadow: '0 1px 4px rgba(0,0,0,0.06)' },
  statVal: { fontSize: 22, fontWeight: 800 },
  statLbl: { fontSize: 11, color: '#888', marginTop: 2 },
};

function SimulationTab() {
  const [liveData, setLiveData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [resetting, setResetting] = useState(false);
  const [actionMsg, setActionMsg] = useState('');
  const [busy, setBusy] = useState(false);
  const [simForm, setSimForm] = useState({ orders: 120, interval: 0.15 });
  const [simStatus, setSimStatus] = useState({ running: false, state: 'IDLE' });

  const fetchLive = useCallback(() => {
    getSimulationLive()
      .then((r) => { setLiveData(r.data); setError(''); })
      .catch(() => setError('Could not load live data'))
      .finally(() => setLoading(false));
  }, []);

  const fetchStatus = useCallback(() => {
    getSimulationStatus()
      .then((r) => setSimStatus(r.data))
      .catch(() => setSimStatus({ running: false, state: 'UNKNOWN' }));
  }, []);

  useWebSocket('/ws/simulation/', () => {
    fetchLive();
    fetchStatus();
  });

  useEffect(() => {
    fetchLive();
    fetchStatus();
    const timer = setInterval(() => {
      fetchLive();
      fetchStatus();
    }, 10000);

    return () => {
      clearInterval(timer);
    };
  }, [fetchLive, fetchStatus]);

  const handleStart = async () => {
    setBusy(true);
    setActionMsg('');
    try {
      const r = await startSimulation({
        orders: Number(simForm.orders),
        interval: Number(simForm.interval),
      });
      setActionMsg(r.data.detail);
      fetchLive();
      fetchStatus();
    } catch (e) {
      setActionMsg(e.response?.data?.detail || 'Could not start simulation');
    } finally {
      setBusy(false);
    }
  };

  const handleStop = async () => {
    setBusy(true);
    setActionMsg('');
    try {
      const r = await stopSimulation();
      setActionMsg(r.data.detail);
      fetchStatus();
    } catch (e) {
      setActionMsg(e.response?.data?.detail || 'Could not stop simulation');
    } finally {
      setBusy(false);
    }
  };

  const handleReset = async () => {
    if (!window.confirm('Reset demo orders and free demo tables?')) return;
    setResetting(true);
    setActionMsg('');
    try {
      const r = await resetSimulation();
      setActionMsg(
        `${r.data.detail} Orders: ${r.data.orders_deleted}, invoices: ${r.data.invoices_deleted}, tables: ${r.data.tables_freed}.`
      );
      setLiveData(null);
      fetchLive();
      fetchStatus();
    } catch (e) {
      setActionMsg(e.response?.data?.detail || 'Reset failed');
    } finally {
      setResetting(false);
    }
  };

  const trendArrow = (pct) => (pct > 0 ? '▲' : pct < 0 ? '▼' : '→');

  return (
    <div>
      <div style={styles.card}>
        <div style={{ ...styles.sectionTitle, marginBottom: 12 }}>Live Simulation</div>
        <div style={styles.row}>
          <div style={{ flex: 1, minWidth: 120 }}>
            <input
              style={styles.input}
              type="number"
              min="1"
              max="500"
              value={simForm.orders}
              onChange={(e) => setSimForm((prev) => ({ ...prev, orders: e.target.value }))}
              disabled={busy || simStatus.running}
              aria-label="Simulation orders"
            />
          </div>
          <div style={{ flex: 1, minWidth: 120 }}>
            <input
              style={styles.input}
              type="number"
              min="0"
              max="10"
              step="0.05"
              value={simForm.interval}
              onChange={(e) => setSimForm((prev) => ({ ...prev, interval: e.target.value }))}
              disabled={busy || simStatus.running}
              aria-label="Simulation interval"
            />
          </div>
          <button style={styles.btn('#16a34a', busy || simStatus.running)} onClick={handleStart} disabled={busy || simStatus.running}>
            {simStatus.running ? 'Running' : 'Start'}
          </button>
          <button style={styles.btn('#f59e0b', busy || !simStatus.running)} onClick={handleStop} disabled={busy || !simStatus.running}>
            Stop
          </button>
          <button style={styles.btn('#e74c3c', resetting)} onClick={handleReset} disabled={resetting}>
            {resetting ? 'Resetting...' : 'Reset Demo Data'}
          </button>
        </div>
        <div style={{ fontSize: 12, color: '#666' }}>
          Status: <strong>{simStatus.state || 'IDLE'}</strong>
          {simStatus.task_id ? ` (${simStatus.task_id.slice(0, 8)})` : ''}
        </div>
      </div>
      {actionMsg && <div style={styles.success}>{actionMsg}</div>}

      {loading && <div style={{ padding: 30, textAlign: 'center', color: '#888' }}>Loading live data...</div>}
      {error && <div style={styles.error}>{error}</div>}

      {liveData && (
        <>
          <div style={simStyles.statRow}>
            {[
              { val: liveData.active_orders, lbl: 'Active Orders' },
              { val: liveData.pending_count, lbl: 'Pending' },
              { val: liveData.preparing_count, lbl: 'Preparing' },
              { val: liveData.ready_count, lbl: 'Ready' },
            ].map(({ val, lbl }) => (
              <div key={lbl} style={simStyles.stat}>
                <div style={simStyles.statVal}>{val}</div>
                <div style={simStyles.statLbl}>{lbl}</div>
              </div>
            ))}
          </div>

          <div style={styles.card}>
            <div style={styles.sectionTitle}>
              Top Dishes — Last {liveData.window_minutes} min
              <span style={{ fontSize: 11, color: '#aaa', fontWeight: 400, marginLeft: 8 }}>
                auto-refreshes every 10s
              </span>
            </div>
            {liveData.top_dishes.length === 0 ? (
              <div style={{ color: '#aaa', fontSize: 13 }}>No order activity yet. Run the simulation first.</div>
            ) : (
              <div style={simStyles.grid}>
                {liveData.top_dishes.map((d) => (
                  <div key={d.id} style={simStyles.liveCard('#fff')}>
                    <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{d.name}</div>
                    <div style={{ fontSize: 12, color: '#666', marginBottom: 6 }}>{d.category}</div>
                    <div style={{ fontSize: 13 }}>
                      <strong>{d.orders_last_window}</strong> orders
                      <span style={simStyles.badge(d.trend_percent)}>
                        {trendArrow(d.trend_percent)} {Math.abs(d.trend_percent)}%
                      </span>
                    </div>
                    <div style={{ fontSize: 11, color: '#888', marginTop: 4 }}>
                      prev: {d.orders_previous_window} → now: {d.orders_last_window}
                    </div>
                    <div style={{ fontSize: 12, fontWeight: 600, marginTop: 6 }}>€{d.current_price}</div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {liveData.recommendations.length > 0 && (
            <div style={styles.card}>
              <div style={styles.sectionTitle}>AI Recommendation Candidates</div>
              <div style={simStyles.grid}>
                {liveData.recommendations.map((r) => (
                  <div key={r.id} style={simStyles.liveCard('#f0fdf4')}>
                    <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{r.name}</div>
                    <div style={{ fontSize: 12, color: '#16a34a', marginBottom: 4 }}>
                      Score: {r.score} &nbsp;
                      <span style={simStyles.badge(r.trend_percent)}>
                        {trendArrow(r.trend_percent)} {Math.abs(r.trend_percent)}%
                      </span>
                    </div>
                    <div style={{ fontSize: 11, color: '#555', fontStyle: 'italic' }}>{r.reason}</div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {liveData.price_changes.length > 0 && (
            <div style={styles.card}>
              <div style={styles.sectionTitle}>Dynamic Pricing — Active Changes</div>
              <div style={simStyles.grid}>
                {liveData.price_changes.map((p) => (
                  <div key={p.id} style={simStyles.liveCard('#fffbeb')}>
                    <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{p.name}</div>
                    <div style={{ fontSize: 13 }}>
                      <span style={{ textDecoration: 'line-through', color: '#888', marginRight: 6 }}>€{p.old_price}</span>
                      <strong>€{p.current_price}</strong>
                      <span style={simStyles.badge(p.change_percent)}>+{p.change_percent}%</span>
                    </div>
                    <div style={{ fontSize: 11, color: '#555', marginTop: 6, fontStyle: 'italic' }}>{p.reason}</div>
                    <div style={{ fontSize: 10, color: '#aaa', marginTop: 4 }}>
                      Rule: &gt;{p.applied_rule.demand_threshold} orders × {p.applied_rule.multiplier}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default function ManagerDashboard() {
  const [activeTab, setActiveTab] = useState('Menu');

  const renderTab = () => {
    switch (activeTab) {
      case 'Menu': return <MenuTab />;
      case 'Staff': return <StaffTab />;
      case 'Pricing': return <PricingTab />;
      case 'Analytics': return <AnalyticsTab />;
      case 'Simulation': return <SimulationTab />;
      default: return null;
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <div style={styles.title}><span style={{ fontFamily: "'Playfair Display', Georgia, serif", fontWeight: 800, letterSpacing: 0, color: '#7c2d12' }}>Walter's</span>&nbsp;·&nbsp;Manager</div>
      </div>
      <div style={styles.tabs}>
        {TABS.map((tab) => (
          <button key={tab} style={styles.tab(activeTab === tab)} onClick={() => setActiveTab(tab)}>
            {tab}
          </button>
        ))}
      </div>
      <div style={styles.content}>
        {renderTab()}
      </div>
    </div>
  );
}
