import React, { useEffect, useState } from 'react';
import { getRecommendations } from '../api/menu';

const styles = {
  section: { marginBottom: 24 },
  title: { fontWeight: 700, fontSize: 14, letterSpacing: 1, color: '#555', marginBottom: 12 },
  grid: { display: 'flex', gap: 12, overflowX: 'auto', paddingBottom: 4 },
  card: {
    minWidth: 160,
    background: 'linear-gradient(135deg, #d97706 0%, #7c2d12 100%)',
    boxShadow: '0 6px 16px -8px rgba(124,45,18,0.6)',
    cursor: 'pointer',
    borderRadius: 12,
    padding: 14,
    color: '#fff',
    flexShrink: 0,
  },
  name: { fontWeight: 700, fontSize: 14, marginBottom: 4 },
  price: { fontSize: 13, opacity: 0.9, marginBottom: 6 },
  reason: { fontSize: 11, opacity: 0.8, lineHeight: 1.4 },
  empty: { color: '#aaa', fontSize: 13 },
};

export default function AIRecommendations({ onAdd }) {
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getRecommendations()
      .then((res) => setRecommendations(res.data.recommendations || []))
      .catch(() => setRecommendations([]))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div style={styles.section}>
        <div style={styles.title}>✨ AI RECOMMENDATIONS</div>
        <div style={styles.empty}>Loading recommendations...</div>
      </div>
    );
  }

  if (recommendations.length === 0) return null;

  return (
    <div style={styles.section}>
      <div style={styles.title}>AI RECOMMENDATIONS</div>
      <div style={styles.grid}>
        {recommendations.map((item) => (
          <div key={item.id} style={styles.card} onClick={() => onAdd && onAdd(item)}>
            <div style={styles.name}>{item.name}</div>
            <div style={styles.price}>${Number(item.price).toFixed(2)}</div>
            {item.reason && <div style={styles.reason}>{item.reason}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}
