import React from 'react';

const STEPS = ['pending', 'preparing', 'ready', 'delivered'];
const LABELS = { pending: 'PENDING', preparing: 'PREPARING', ready: 'READY', delivered: 'DELIVERED' };
const DESCRIPTIONS = {
  pending: 'Your order has been placed and is waiting for the kitchen.',
  preparing: 'The kitchen is preparing your order.',
  ready: 'Your order is ready! A waiter will bring it to you.',
  delivered: 'Your order has been delivered. Enjoy your meal!',
};

const styles = {
  container: { padding: '16px 0' },
  steps: { display: 'flex', alignItems: 'center', marginBottom: 16 },
  step: (active, done) => ({
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    position: 'relative',
  }),
  circle: (active, done) => ({
    width: 32,
    height: 32,
    borderRadius: '50%',
    background: done ? '#27ae60' : active ? '#222' : '#ddd',
    color: '#fff',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontWeight: 700,
    fontSize: 14,
    zIndex: 1,
    border: active && !done ? '2px solid #222' : 'none',
  }),
  label: (active, done) => ({
    fontSize: 10,
    fontWeight: 600,
    marginTop: 6,
    color: done ? '#27ae60' : active ? '#222' : '#aaa',
    textAlign: 'center',
  }),
  connector: (done) => ({
    position: 'absolute',
    top: 15,
    left: '50%',
    width: '100%',
    height: 3,
    background: done ? '#27ae60' : '#ddd',
    zIndex: 0,
  }),
  desc: {
    textAlign: 'center',
    color: '#555',
    fontSize: 14,
    padding: '8px 16px',
    background: '#f9f9f9',
    borderRadius: 8,
  },
};

export default function StatusBar({ status }) {
  const currentIdx = STEPS.indexOf(status);

  return (
    <div style={styles.container}>
      <div style={styles.steps}>
        {STEPS.map((step, idx) => {
          const done = idx < currentIdx;
          const active = idx === currentIdx;
          return (
            <div key={step} style={styles.step(active, done)}>
              {idx < STEPS.length - 1 && (
                <div style={styles.connector(done || active)} />
              )}
              <div style={styles.circle(active, done)}>
                {done ? '✓' : idx + 1}
              </div>
              <div style={styles.label(active, done)}>{LABELS[step]}</div>
            </div>
          );
        })}
      </div>
      <div style={styles.desc}>{DESCRIPTIONS[status] || ''}</div>
    </div>
  );
}
