import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { placeOrder } from '../api/orders';
import { getMyTable } from '../api/tables';

const styles = {
  page: { minHeight: '100vh', background: '#f5f5f5' },
  header: {
    background: '#fff',
    padding: '14px 20px',
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
  },
  backBtn: { background: 'none', border: 'none', fontSize: 22, cursor: 'pointer', padding: 0 },
  title: { fontWeight: 700, fontSize: 18 },
  tableInfo: { fontSize: 13, color: '#888', marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 8 },
  refreshBtn: { background: 'none', border: '1px solid #ddd', borderRadius: 6, fontSize: 12, padding: '3px 8px', cursor: 'pointer', color: '#555' },
  noTable: { fontSize: 13, color: '#e74c3c', marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 8 },
  content: { padding: 20, maxWidth: 500, margin: '0 auto' },
  card: {
    background: '#fff',
    borderRadius: 12,
    padding: 16,
    marginBottom: 16,
    boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
  },
  sectionTitle: { fontWeight: 600, fontSize: 13, color: '#555', marginBottom: 12 },
  item: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 },
  itemName: { fontWeight: 500, fontSize: 14, flex: 1 },
  qtyControls: { display: 'flex', alignItems: 'center', gap: 8 },
  qtyBtn: {
    width: 28,
    height: 28,
    borderRadius: '50%',
    border: '1.5px solid #ddd',
    background: '#fff',
    fontWeight: 700,
    fontSize: 16,
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  qty: { fontWeight: 600, fontSize: 14, minWidth: 20, textAlign: 'center' },
  subtotal: { fontSize: 13, color: '#666', minWidth: 60, textAlign: 'right' },
  textarea: {
    width: '100%',
    padding: '10px 12px',
    borderRadius: 8,
    border: '1.5px solid #e0e0e0',
    fontSize: 13,
    outline: 'none',
    resize: 'vertical',
    minHeight: 80,
    boxSizing: 'border-box',
  },
  total: { fontWeight: 700, fontSize: 18, textAlign: 'right', marginTop: 8 },
  empty: { textAlign: 'center', color: '#aaa', padding: 24, fontSize: 14 },
  error: {
    background: '#fde8e8',
    color: '#e74c3c',
    borderRadius: 8,
    padding: '10px 14px',
    fontSize: 13,
    marginBottom: 12,
  },
  actions: { display: 'flex', gap: 10, marginTop: 16 },
  btn: (primary, disabled) => ({
    flex: 1,
    padding: '12px',
    borderRadius: 8,
    border: primary ? 'none' : '1.5px solid #ddd',
    background: disabled ? '#ccc' : primary ? '#222' : '#fff',
    color: primary ? '#fff' : '#333',
    fontWeight: 600,
    fontSize: 14,
    cursor: disabled ? 'not-allowed' : 'pointer',
  }),
};

export default function OrderPlacement() {
  const navigate = useNavigate();
  const [cart, setCart] = useState([]);
  const [tableId, setTableId] = useState(null);
  const [tableNumber, setTableNumber] = useState(null);
  const [specialRequests, setSpecialRequests] = useState('');
  const [loading, setLoading] = useState(false);
  const [tableLoading, setTableLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchTable = () => {
    setTableLoading(true);
    getMyTable().then((res) => {
      const table = res.data.table;
      if (table) {
        setTableId(table.id);
        setTableNumber(table.table_number);
      } else {
        setTableId(null);
        setTableNumber(null);
      }
    }).catch((err) => {
      const msg = err.response?.data?.detail || err.message || 'Unknown error';
      setError(`Could not fetch table: ${msg}`);
    }).finally(() => setTableLoading(false));
  };

  useEffect(() => {
    try {
      const saved = JSON.parse(localStorage.getItem('cart') || '[]');
      setCart(saved);
    } catch (_) {}
    fetchTable();
  }, []);

  const updateQty = (id, delta) => {
    const updated = cart
      .map((i) => i.id === id ? { ...i, quantity: i.quantity + delta } : i)
      .filter((i) => i.quantity > 0);
    setCart(updated);
    localStorage.setItem('cart', JSON.stringify(updated));
  };

  const total = cart.reduce((s, i) => s + Number(i.price) * i.quantity, 0);

  const handleConfirm = async () => {
    setError('');
    if (!tableId) {
      setError('No table assigned. Ask a waiter to assign you a table.');
      return;
    }
    if (cart.length === 0) {
      setError('Your cart is empty.');
      return;
    }
    setLoading(true);
    try {
      const res = await placeOrder({
        table_id: tableId,
        items: cart.map((i) => ({ menu_item_id: i.id, quantity: i.quantity })),
        special_requests: specialRequests || undefined,
      });
      localStorage.removeItem('cart');
      localStorage.setItem('current_order_id', res.data.id);
      navigate('/track');
    } catch (err) {
      const msg = err.response?.data?.detail || 'Failed to place order';
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <button style={styles.backBtn} onClick={() => navigate('/menu')}>←</button>
        <div style={styles.title}>PLACE ORDER</div>
        {tableLoading ? (
          <div style={styles.tableInfo}>Checking table...</div>
        ) : tableNumber ? (
          <div style={styles.tableInfo}>
            Table: {tableNumber}
            <button style={styles.refreshBtn} onClick={fetchTable}>↻</button>
          </div>
        ) : (
          <div style={styles.noTable}>
            No table assigned
            <button style={styles.refreshBtn} onClick={fetchTable}>↻ Refresh</button>
          </div>
        )}
      </div>

      <div style={styles.content}>
        {error && <div style={styles.error}>{error}</div>}

        <div style={styles.card}>
          <div style={styles.sectionTitle}>ORDER ITEMS</div>
          {cart.length === 0 ? (
            <div style={styles.empty}>Your cart is empty. Go back and add items.</div>
          ) : (
            cart.map((item) => (
              <div key={item.id} style={styles.item}>
                <div style={styles.itemName}>{item.name}</div>
                <div style={styles.qtyControls}>
                  <button style={styles.qtyBtn} onClick={() => updateQty(item.id, -1)}>-</button>
                  <span style={styles.qty}>{item.quantity}</span>
                  <button style={styles.qtyBtn} onClick={() => updateQty(item.id, 1)}>+</button>
                </div>
                <div style={styles.subtotal}>
                  ${(Number(item.price) * item.quantity).toFixed(2)}
                </div>
              </div>
            ))
          )}
          {cart.length > 0 && (
            <div style={styles.total}>TOTAL: ${total.toFixed(2)}</div>
          )}
        </div>

        <div style={styles.card}>
          <div style={styles.sectionTitle}>SPECIAL REQUESTS</div>
          <textarea
            style={styles.textarea}
            placeholder="Allergies, preferences, notes..."
            value={specialRequests}
            onChange={(e) => setSpecialRequests(e.target.value)}
            disabled={loading}
          />
        </div>

        <div style={styles.actions}>
          <button style={styles.btn(false, false)} onClick={() => navigate('/menu')}>
            BACK TO MENU
          </button>
          <button
            style={styles.btn(true, loading || cart.length === 0)}
            onClick={handleConfirm}
            disabled={loading || cart.length === 0}
          >
            {loading ? 'Placing...' : 'CONFIRM ORDER'}
          </button>
        </div>
      </div>
    </div>
  );
}
