import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ROLES = [
  { key: 'customer', username: 'sam', emoji: '🍽️', title: 'Diner', route: '/menu',
    desc: 'Browse the photo menu, get AI picks, place an order and track it live.' },
  { key: 'kitchen', username: 'lena', emoji: '🔥', title: 'Kitchen', route: '/kitchen',
    desc: 'A live kitchen display — fire tickets and mark dishes ready in real time.' },
  { key: 'waiter', username: 'marcus', emoji: '🛎️', title: 'Waiter', route: '/waiter',
    desc: 'Pick up ready orders, run the floor and manage the table map.' },
  { key: 'manager', username: 'nadia', emoji: '📊', title: 'Manager', route: '/manager',
    desc: 'Analytics, AI dynamic pricing and a live demand simulation.' },
];

const styles = {
  page: {
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '40px 20px',
    background: 'radial-gradient(1100px 600px at 70% -10%, #3a2417 0%, #1c1206 55%, #140d05 100%)',
    fontFamily: "'Inter', system-ui, sans-serif",
  },
  brandRow: { display: 'flex', alignItems: 'center', gap: 12, marginBottom: 6 },
  dot: { width: 12, height: 12, borderRadius: '50%', background: 'linear-gradient(135deg,#f59e0b,#b45309)' },
  brand: { fontFamily: "'Playfair Display', Georgia, serif", fontWeight: 700, fontSize: 40, color: '#fdf6ec', letterSpacing: 0.5 },
  tagline: { color: '#caa985', fontSize: 14, letterSpacing: 3, textTransform: 'uppercase', marginBottom: 4 },
  demoNote: { color: '#b79b78', fontSize: 13.5, marginBottom: 30, textAlign: 'center', maxWidth: 520 },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
    gap: 18,
    width: '100%',
    maxWidth: 920,
  },
  card: (busy) => ({
    position: 'relative',
    background: 'rgba(255,255,255,0.04)',
    border: '1px solid rgba(245,158,11,0.22)',
    borderRadius: 16,
    padding: '24px 22px',
    cursor: busy ? 'wait' : 'pointer',
    transition: 'transform .16s ease, border-color .16s ease, background .16s ease',
    textAlign: 'left',
    color: '#fdf6ec',
  }),
  emoji: { fontSize: 30, marginBottom: 12, display: 'block' },
  cardTitle: { fontSize: 19, fontWeight: 700, marginBottom: 6, fontFamily: "'Playfair Display', Georgia, serif" },
  cardDesc: { fontSize: 13.5, color: '#c9b59c', lineHeight: 1.5, marginBottom: 14 },
  enter: { fontSize: 13, fontWeight: 700, color: '#f59e0b', display: 'inline-flex', alignItems: 'center', gap: 6 },
  footer: { marginTop: 30, color: '#8c7458', fontSize: 12.5, textAlign: 'center' },
};

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [busy, setBusy] = useState('');

  const enter = async (role) => {
    if (busy) return;
    setBusy(role.key);
    try {
      await login(role.username, 'demo');
      navigate(role.route);
    } catch {
      setBusy('');
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.brandRow}>
        <span style={styles.dot} />
        <span style={styles.brand}>Walter's</span>
      </div>
      <div style={styles.tagline}>Smart Restaurant Platform</div>
      <div style={styles.demoNote}>
        Interactive demo — running on sample data, no sign-up. Pick a role to explore the
        product from that person's seat.
      </div>

      <div style={styles.grid}>
        {ROLES.map((role) => (
          <div
            key={role.key}
            style={styles.card(busy === role.key)}
            onClick={() => enter(role)}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.borderColor = 'rgba(245,158,11,0.55)';
              e.currentTarget.style.background = 'rgba(245,158,11,0.07)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'none';
              e.currentTarget.style.borderColor = 'rgba(245,158,11,0.22)';
              e.currentTarget.style.background = 'rgba(255,255,255,0.04)';
            }}
          >
            <span style={styles.emoji}>{role.emoji}</span>
            <div style={styles.cardTitle}>{role.title}</div>
            <div style={styles.cardDesc}>{role.desc}</div>
            <span style={styles.enter}>
              {busy === role.key ? 'Entering…' : 'Enter →'}
            </span>
          </div>
        ))}
      </div>

      <div style={styles.footer}>
        Built by Alex B · multi-role restaurant ops — ordering, kitchen, service, and management.
      </div>
    </div>
  );
}
