import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { register } from '../api/auth';

const styles = {
  page: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)',
  },
  card: {
    background: '#fff',
    borderRadius: 16,
    padding: '40px 36px',
    width: '100%',
    maxWidth: 420,
    boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
  },
  logo: { fontWeight: 800, fontSize: 22, letterSpacing: 2, color: '#222', marginBottom: 4 },
  subtitle: { fontSize: 13, color: '#888', marginBottom: 28 },
  label: { fontSize: 12, fontWeight: 600, color: '#555', display: 'block', marginBottom: 6 },
  input: (hasError) => ({
    width: '100%',
    padding: '10px 14px',
    borderRadius: 8,
    border: `1.5px solid ${hasError ? '#e74c3c' : '#e0e0e0'}`,
    fontSize: 14,
    outline: 'none',
    marginBottom: 4,
    boxSizing: 'border-box',
  }),
  fieldError: { color: '#e74c3c', fontSize: 11, marginBottom: 12 },
  btn: (loading) => ({
    width: '100%',
    padding: '12px',
    borderRadius: 8,
    border: 'none',
    background: loading ? '#aaa' : '#222',
    color: '#fff',
    fontWeight: 700,
    fontSize: 15,
    cursor: loading ? 'not-allowed' : 'pointer',
    marginTop: 8,
  }),
  success: {
    background: '#d4edda',
    color: '#155724',
    borderRadius: 8,
    padding: '10px 14px',
    fontSize: 13,
    marginBottom: 16,
  },
  link: { textAlign: 'center', marginTop: 18, fontSize: 13, color: '#888' },
};

export default function RegisterPage() {
  const [form, setForm] = useState({ username: '', email: '', phone: '', password: '' });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const navigate = useNavigate();

  const set = (field) => (e) => setForm((p) => ({ ...p, [field]: e.target.value }));

  const handleSubmit = async () => {
    setErrors({});
    setLoading(true);
    try {
      await register(form);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 1500);
    } catch (err) {
      const data = err.response?.data;
      if (data && typeof data === 'object') {
        setErrors(data);
      } else {
        setErrors({ non_field_errors: ['Registration failed'] });
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={{ ...styles.logo, fontFamily: "'Playfair Display', Georgia, serif", color: '#7c2d12' }}>Walter's</div>
        <div style={styles.subtitle}>Create your customer account</div>

        {success && <div style={styles.success}>Account created! Redirecting to login...</div>}
        {errors.non_field_errors && (
          <div style={{ color: '#e74c3c', fontSize: 13, marginBottom: 12 }}>
            {errors.non_field_errors.join(', ')}
          </div>
        )}
        {errors.detail && (
          <div style={{ color: '#e74c3c', fontSize: 13, marginBottom: 12 }}>{errors.detail}</div>
        )}

        {[
          { field: 'username', label: 'Username', type: 'text', placeholder: 'Choose a username' },
          { field: 'email', label: 'Email', type: 'email', placeholder: 'your@email.com' },
          { field: 'phone', label: 'Phone (optional)', type: 'tel', placeholder: '+1 555 000 0000' },
          { field: 'password', label: 'Password', type: 'password', placeholder: 'Min 8 characters' },
        ].map(({ field, label, type, placeholder }) => (
          <div key={field}>
            <label style={styles.label}>{label}</label>
            <input
              style={styles.input(!!errors[field])}
              type={type}
              placeholder={placeholder}
              value={form[field]}
              onChange={set(field)}
              disabled={loading || success}
            />
            {errors[field] && (
              <div style={styles.fieldError}>{errors[field].join(', ')}</div>
            )}
          </div>
        ))}

        <button style={styles.btn(loading || success)} onClick={handleSubmit} disabled={loading || success}>
          {loading ? 'Creating account...' : 'CREATE ACCOUNT'}
        </button>

        <div style={styles.link}>
          Already have an account?{' '}
          <Link to="/login" style={{ color: '#4f46e5', fontWeight: 600 }}>
            Sign In
          </Link>
        </div>
      </div>
    </div>
  );
}
