import React, { useEffect, useState, useCallback } from 'react';
import { getKitchenOrders, updateStatus } from '../api/orders';
import { useWebSocket } from '../hooks/useWebSocket';
import OrderCard from '../components/OrderCard';

const styles = {
  page: { minHeight: '100vh', background: '#1a1a2e' },
  header: {
    background: '#16213e',
    padding: '16px 24px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    borderBottom: '1px solid #0f3460',
  },
  title: { fontWeight: 800, fontSize: 20, color: '#fff', letterSpacing: 2 },
  count: {
    background: '#e74c3c',
    color: '#fff',
    borderRadius: 20,
    padding: '4px 14px',
    fontWeight: 700,
    fontSize: 14,
  },
  content: { padding: 20 },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: 16,
  },
  empty: { textAlign: 'center', color: '#555', padding: 60, fontSize: 16 },
  error: { background: '#3d1515', color: '#e74c3c', borderRadius: 8, padding: 12, marginBottom: 16, fontSize: 13 },
};

export default function KitchenDisplay() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchOrders = useCallback(async () => {
    try {
      const res = await getKitchenOrders();
      setOrders(res.data);
    } catch (_) {
      setError('Failed to load orders');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchOrders(); }, [fetchOrders]);

  const handleWsMessage = useCallback((data) => {
    if (data.type === 'new_order') {
      setOrders((prev) => {
        if (prev.find((o) => o.id === data.order_id)) return prev;
        return [{
          id: data.order_id,
          table_number: data.table_number,
          items: data.items || [],
          status: 'pending',
          created_at: data.created_at,
        }, ...prev];
      });
    } else if (data.type === 'order_status_update') {
      setOrders((prev) =>
        prev
          .map((o) => o.id === data.order_id ? { ...o, status: data.status } : o)
          .filter((o) => ['pending', 'preparing'].includes(o.status))
      );
    } else if (data.type === 'order_cancelled') {
      setOrders((prev) => prev.filter((o) => o.id !== data.order_id));
    }
  }, []);

  useWebSocket('/ws/kitchen/', handleWsMessage);

  const handleAction = async (order) => {
    const nextStatus = order.status === 'pending' ? 'preparing' : 'ready';
    try {
      await updateStatus(order.id, nextStatus);
      setOrders((prev) =>
        prev
          .map((o) => o.id === order.id ? { ...o, status: nextStatus } : o)
          .filter((o) => ['pending', 'preparing'].includes(o.status))
      );
    } catch (_) {
      fetchOrders();
    }
  };

  const getActionLabel = (order) =>
    order.status === 'pending' ? 'START PREPARING' : 'MARK AS READY';

  const activeCount = orders.length;

  if (loading) return <div style={{ padding: 40, textAlign: 'center', color: '#fff' }}>Loading...</div>;

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <div style={styles.title}><span style={{ fontFamily: "'Playfair Display', Georgia, serif", fontWeight: 800, letterSpacing: 0 }}>Walter's</span>&nbsp;·&nbsp;Kitchen</div>
        <div style={styles.count}>Orders: {activeCount} active</div>
      </div>
      <div style={styles.content}>
        {error && <div style={styles.error}>{error}</div>}
        {orders.length === 0 ? (
          <div style={styles.empty}>No active orders</div>
        ) : (
          <div style={styles.grid}>
            {orders.map((order) => (
              <OrderCard
                key={order.id}
                order={order}
                onAction={handleAction}
                actionLabel={getActionLabel(order)}
                actionColor={order.status === 'pending' ? '#e67e22' : '#27ae60'}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
