import axios from 'axios';

export const getAnalytics = (period = 'day') =>
  axios.get('/api/manager/analytics/', { params: { period } });

export const createStaff = (data) =>
  axios.post('/api/manager/staff/', data);

export const getInvoices = (params = {}) =>
  axios.get('/api/manager/invoices/', { params });

export const getPricingRules = () =>
  axios.get('/api/manager/pricing/');

export const createPricingRule = (data) =>
  axios.post('/api/manager/pricing/', data);

export const deletePricingRule = (id) =>
  axios.delete(`/api/manager/pricing/${id}/`);

export const getSimulationLive = () =>
  axios.get('/api/manager/simulation/live/');

export const startSimulation = (data) =>
  axios.post('/api/manager/simulation/start/', data);

export const stopSimulation = () =>
  axios.post('/api/manager/simulation/stop/');

export const getSimulationStatus = () =>
  axios.get('/api/manager/simulation/status/');

export const resetSimulation = () =>
  axios.post('/api/manager/simulation/reset/');
