import React, { useEffect, useState, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getMenu } from '../api/menu';
import MenuCard from '../components/MenuCard';
import AIRecommendations from '../components/AIRecommendations';

const styles = {
  page: { minHeight: '100vh', background: '#f5f5f5', paddingBottom: 70 },
  header: {
    background: '#fff',
    padding: '14px 20px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
    position: 'sticky',
    top: 0,
    zIndex: 100,
  },
  logo: { fontFamily: "'Playfair Display', Georgia, serif", fontWeight: 800, fontSize: 21, color: '#7c2d12', display: 'flex', alignItems: 'center', gap: 8 },
  logoDot: { width: 9, height: 9, borderRadius: '50%', background: 'linear-gradient(135deg,#f59e0b,#b45309)', display: 'inline-block' },
  userRow: { display: 'flex', alignItems: 'center', gap: 10 },
  username: { fontSize: 13, color: '#555' },
  logoutBtn: {
    padding: '5px 14px',
    borderRadius: 6,
    border: '1px solid #ddd',
    background: '#fff',
    fontSize: 12,
    cursor: 'pointer',
  },
  content: { padding: '20px 16px' },
  searchBar: {
    width: '100%',
    padding: '10px 16px',
    borderRadius: 10,
    border: '1.5px solid #e0e0e0',
    fontSize: 14,
    outline: 'none',
    marginBottom: 20,
    boxSizing: 'border-box',
    background: '#fff',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))',
    gap: 16,
  },
  skeleton: {
    height: 240,
    background: 'linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%)',
    borderRadius: 12,
    animation: 'pulse 1.5s infinite',
  },
  empty: { textAlign: 'center', color: '#aaa', padding: 40, fontSize: 15 },
  nav: {
    position: 'fixed',
    bottom: 0,
    left: 0,
    right: 0,
    background: '#fff',
    borderTop: '1px solid #eee',
    display: 'flex',
    zIndex: 100,
  },
  navBtn: (active) => ({
    flex: 1,
    padding: '12px 0',
    border: 'none',
    background: 'none',
    fontWeight: active ? 700 : 500,
    fontSize: 12,
    color: active ? '#7c2d12' : '#999',
    cursor: 'pointer',
    borderTop: active ? '2px solid #7c2d12' : '2px solid transparent',
  }),
  catFilter: { display: 'flex', gap: 8, overflowX: 'auto', marginBottom: 16, paddingBottom: 4 },
  catBtn: (active) => ({
    padding: '5px 14px',
    borderRadius: 20,
    border: '1.5px solid',
    borderColor: active ? '#7c2d12' : '#ddd',
    background: active ? '#7c2d12' : '#fff',
    color: active ? '#fff' : '#555',
    fontSize: 12,
    fontWeight: 600,
    cursor: 'pointer',
    whiteSpace: 'nowrap',
  }),
};

export default function CustomerMenu() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('');
  const [cart, setCart] = useState(() => {
    try { return JSON.parse(localStorage.getItem('cart') || '[]'); } catch { return []; }
  });
  const debounceRef = useRef(null);

  const fetchMenu = useCallback((q, cat) => {
    setLoading(true);
    const params = { available: true };
    if (q) params.search = q;
    if (cat) params.category = cat;
    getMenu(params)
      .then((res) => {
        const data = res.data;
        setItems(Array.isArray(data) ? data : (data.results || []));
      })
      .catch(() => setItems([]))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { fetchMenu('', ''); }, [fetchMenu]);

  const handleSearchChange = (e) => {
    const val = e.target.value;
    setSearch(val);
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => fetchMenu(val, category), 300);
  };

  const handleCategoryChange = (cat) => {
    setCategory(cat);
    fetchMenu(search, cat);
  };

  const addToCart = (item) => {
    const updated = [...cart];
    const idx = updated.findIndex((i) => i.id === item.id);
    if (idx >= 0) {
      updated[idx] = { ...updated[idx], quantity: updated[idx].quantity + 1 };
    } else {
      updated.push({ ...item, quantity: 1 });
    }
    setCart(updated);
    localStorage.setItem('cart', JSON.stringify(updated));
  };

  const categories = [...new Set(items.map((i) => i.category))].filter(Boolean);
  const cartCount = cart.reduce((s, i) => s + i.quantity, 0);

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <div style={styles.logo}><span style={styles.logoDot} />Walter's</div>
        <div style={styles.userRow}>
          <span style={styles.username}>Welcome, {user?.username}</span>
          <button style={styles.logoutBtn} onClick={handleLogout}>Logout</button>
        </div>
      </div>

      <div style={styles.content}>
        <input
          style={styles.searchBar}
          placeholder="Search dishes..."
          value={search}
          onChange={handleSearchChange}
        />

        {categories.length > 0 && (
          <div style={styles.catFilter}>
            <button style={styles.catBtn(!category)} onClick={() => handleCategoryChange('')}>
              All
            </button>
            {categories.map((cat) => (
              <button key={cat} style={styles.catBtn(category === cat)} onClick={() => handleCategoryChange(cat)}>
                {cat}
              </button>
            ))}
          </div>
        )}

        <AIRecommendations onAdd={addToCart} />

        {loading ? (
          <div style={styles.grid}>
            {[...Array(6)].map((_, i) => <div key={i} style={styles.skeleton} />)}
          </div>
        ) : items.length === 0 ? (
          <div style={styles.empty}>No items found</div>
        ) : (
          <div style={styles.grid}>
            {items.map((item) => (
              <MenuCard key={item.id} item={item} onAdd={addToCart} />
            ))}
          </div>
        )}
      </div>

      <div style={styles.nav}>
        <button style={styles.navBtn(true)}>MENU</button>
        <button style={styles.navBtn(false)} onClick={() => navigate('/order')}>
          MY ORDER{cartCount > 0 ? ` (${cartCount})` : ''}
        </button>
        <button style={styles.navBtn(false)} onClick={() => navigate('/track')}>TRACK</button>
        <button style={styles.navBtn(false)} onClick={() => navigate('/track')}>BILL</button>
      </div>
    </div>
  );
}
