import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ROLE_LABEL = { customer: 'Diner', kitchen_staff: 'Kitchen', waiter: 'Waiter', manager: 'Manager' };

/**
 * Floating demo control shown on every authenticated page. Lets a visitor hop
 * between the four roles without hunting for credentials. Customer pages have a
 * fixed bottom nav, so the pill is lifted above it for that role.
 */
export default function DemoControls() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  if (!user) return null;

  const switchRole = async () => {
    await logout();
    navigate('/login');
  };

  const bottom = user.role === 'customer' ? 78 : 18;

  return (
    <div
      style={{
        position: 'fixed', left: 18, bottom, zIndex: 9999,
        display: 'flex', alignItems: 'center', gap: 10,
        background: 'rgba(20,13,5,0.92)', color: '#fdf6ec',
        border: '1px solid rgba(245,158,11,0.4)', borderRadius: 999,
        padding: '7px 8px 7px 14px', boxShadow: '0 10px 28px -12px rgba(0,0,0,0.7)',
        fontSize: 12.5, backdropFilter: 'blur(6px)',
      }}
    >
      <span style={{ display: 'inline-flex', alignItems: 'center', gap: 7, whiteSpace: 'nowrap' }}>
        <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#f59e0b' }} />
        Demo · <b style={{ fontWeight: 700 }}>{ROLE_LABEL[user.role] || user.role}</b>
      </span>
      <button
        onClick={switchRole}
        style={{
          border: 'none', cursor: 'pointer', background: '#b45309', color: '#fff',
          fontWeight: 700, fontSize: 12, borderRadius: 999, padding: '6px 12px',
        }}
      >
        Switch role ⇄
      </button>
    </div>
  );
}
