import React from 'react';

const styles = {
  card: {
    background: '#fff',
    borderRadius: 12,
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
  },
  img: {
    width: '100%',
    height: 160,
    objectFit: 'cover',
    background: '#eee',
  },
  imgPlaceholder: {
    width: '100%',
    height: 160,
    background: '#e8e8e8',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: '#aaa',
    fontSize: 14,
  },
  body: { padding: '12px 14px 14px' },
  name: { fontWeight: 600, fontSize: 15, marginBottom: 4 },
  desc: { fontSize: 12, color: '#777', marginBottom: 8, lineHeight: 1.4 },
  row: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 8 },
  price: { fontWeight: 700, fontSize: 16, color: '#222' },
  badge: (available) => ({
    fontSize: 11,
    fontWeight: 600,
    padding: '2px 8px',
    borderRadius: 20,
    background: available ? '#e6f9ee' : '#fde8e8',
    color: available ? '#27ae60' : '#e74c3c',
  }),
  addBtn: (available) => ({
    padding: '6px 16px',
    borderRadius: 8,
    border: 'none',
    background: available ? '#7c2d12' : '#ccc',
    color: '#fff',
    fontWeight: 600,
    fontSize: 13,
    cursor: available ? 'pointer' : 'not-allowed',
  }),
};

export default function MenuCard({ item, onAdd }) {
  return (
    <div style={styles.card}>
      {item.image_url ? (
        <img src={item.image_url} alt={item.name} style={styles.img} />
      ) : (
        <div style={styles.imgPlaceholder}>No image</div>
      )}
      <div style={styles.body}>
        <div style={styles.name}>{item.name}</div>
        {item.description && <div style={styles.desc}>{item.description}</div>}
        <div style={styles.row}>
          <div>
            <div style={styles.price}>${Number(item.price).toFixed(2)}</div>
            <span style={styles.badge(item.available)}>
              {item.available ? 'AVAILABLE' : 'UNAVAILABLE'}
            </span>
          </div>
          <button
            style={styles.addBtn(item.available)}
            disabled={!item.available}
            onClick={() => item.available && onAdd(item)}
          >
            ADD
          </button>
        </div>
      </div>
    </div>
  );
}
