import React, { useEffect, useState, useCallback } from 'react';
import { getWaiterOrders, updateStatus } from '../api/orders';
import { getTables, assignTable } from '../api/tables';
import { useWebSocket } from '../hooks/useWebSocket';
import OrderCard from '../components/OrderCard';
import TableMap from '../components/TableMap';

const styles = {
  page: { minHeight: '100vh', background: '#f5f5f5' },
  header: {
    background: '#fff',
    padding: '14px 20px',
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
  },
  title: { fontWeight: 800, fontSize: 18, letterSpacing: 1 },
  content: { padding: 20, maxWidth: 900, margin: '0 auto' },
  section: { marginBottom: 28 },
  sectionTitle: { fontWeight: 700, fontSize: 14, letterSpacing: 1, color: '#555', marginBottom: 12 },
  card: {
    background: '#fff', borderRadius: 12, padding: 16,
    boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
  },
  assignRow: { display: 'flex', gap: 10, marginTop: 16, flexWrap: 'wrap' },
  input: {
    flex: 1, minWidth: 120, padding: '8px 12px',
    borderRadius: 8, border: '1.5px solid #ddd',
    fontSize: 13, outline: 'none',
  },
  assignBtn: (loading) => ({
    padding: '8px 20px', borderRadius: 8, border: 'none',
    background: loading ? '#ccc' : '#222', color: '#fff',
    fontWeight: 600, fontSize: 13, cursor: loading ? 'not-allowed' : 'pointer',
  }),
  error: { background: '#fde8e8', color: '#e74c3c', borderRadius: 8, padding: '8px 12px', fontSize: 13, marginBottom: 12 },
  success: { background: '#d4edda', color: '#155724', borderRadius: 8, padding: '8px 12px', fontSize: 13, marginBottom: 12 },
  empty: { color: '#aaa', fontSize: 13, padding: '10px 0' },
};

export default function WaiterDashboard() {
  const [orders, setOrders] = useState([]);
  const [tables, setTables] = useState([]);
  const [customerUsername, setCustomerUsername] = useState('');
  const [tableId, setTableId] = useState('');
  const [assignLoading, setAssignLoading] = useState(false);
  const [assignError, setAssignError] = useState('');
  const [assignSuccess, setAssignSuccess] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      const [ordersRes, tablesRes] = await Promise.all([getWaiterOrders(), getTables()]);
      setOrders(ordersRes.data);
      setTables(tablesRes.data);
    } catch (_) {}
    finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleWsMessage = useCallback((data) => {
    if (data.type === 'order_ready') {
      fetchData();
    } else if (data.type === 'order_status_update') {
      setOrders((prev) =>
        data.status === 'delivered'
          ? prev.filter((o) => o.id !== data.order_id)
          : prev
      );
    }
  }, [fetchData]);

  useWebSocket('/ws/waiter/', handleWsMessage);

  const handleDeliver = async (order) => {
    try {
      await updateStatus(order.id, 'delivered');
      setOrders((prev) => prev.filter((o) => o.id !== order.id));
      fetchData();
    } catch (_) {}
  };

  const handleAssign = async () => {
    setAssignError('');
    setAssignSuccess('');
    if (!customerUsername || !tableId) {
      setAssignError('Enter both customer username and table number');
      return;
    }
    setAssignLoading(true);
    try {
      const table = tables.find((t) => t.table_number === Number(tableId));
      if (!table) {
        setAssignError('Table not found');
        setAssignLoading(false);
        return;
      }
      await assignTable(table.id, null, customerUsername);
      setAssignSuccess(`Table ${tableId} assigned to @${customerUsername}`);
      setCustomerUsername('');
      setTableId('');
      fetchData();
    } catch (err) {
      setAssignError(err.response?.data?.detail || 'Assignment failed');
    } finally {
      setAssignLoading(false);
    }
  };

  if (loading) return <div style={{ padding: 40, textAlign: 'center' }}>Loading...</div>;

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <div style={styles.title}><span style={{ fontFamily: "'Playfair Display', Georgia, serif", fontWeight: 800, letterSpacing: 0, color: '#7c2d12' }}>Walter's</span>&nbsp;·&nbsp;Service</div>
      </div>
      <div style={styles.content}>

        <div style={styles.section}>
          <div style={styles.sectionTitle}>DELIVERY QUEUE</div>
          {orders.length === 0 ? (
            <div style={styles.empty}>No orders ready for delivery</div>
          ) : (
            orders.map((order) => (
              <OrderCard
                key={order.id}
                order={order}
                onAction={handleDeliver}
                actionLabel="DELIVER"
                actionColor="#27ae60"
              />
            ))
          )}
        </div>

        <div style={styles.section}>
          <div style={styles.card}>
            <div style={styles.sectionTitle}>TABLE MAP</div>
            <TableMap tables={tables} />

            <div style={{ marginTop: 20 }}>
              <div style={styles.sectionTitle}>ASSIGN TABLE</div>
              {assignError && <div style={styles.error}>{assignError}</div>}
              {assignSuccess && <div style={styles.success}>{assignSuccess}</div>}
              <div style={styles.assignRow}>
                <input
                  style={styles.input}
                  placeholder="Customer username"
                  value={customerUsername}
                  onChange={(e) => setCustomerUsername(e.target.value)}
                  disabled={assignLoading}
                />
                <input
                  style={styles.input}
                  placeholder="Table #"
                  type="number"
                  value={tableId}
                  onChange={(e) => setTableId(e.target.value)}
                  disabled={assignLoading}
                />
                <button style={styles.assignBtn(assignLoading)} onClick={handleAssign} disabled={assignLoading}>
                  {assignLoading ? '...' : 'GO'}
                </button>
              </div>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}
