// ---- Router ----------------------------------------------------------------
function getParam(config, key) {
  if (config.params && key in config.params) return config.params[key];
  const u = config.url || '';
  const qi = u.indexOf('?');
  if (qi !== -1) return new URLSearchParams(u.slice(qi + 1)).get(key);
  return undefined;
}

function route(method, seg, config) {
  const body = (() => { try { return typeof config.data === 'string' ? JSON.parse(config.data) : config.data; } catch { return config.data; } })() || {};
  let m;

  // --- auth ---
  if (method === 'post' && seg === '/api/auth/login') {
    const role = USERNAME_TO_ROLE[String(body.username || '').toLowerCase()] || 'customer';
    return { token: `demo-token-${role}`, user: USERS[role] };
  }
  if (method === 'post' && seg === '/api/auth/register') return { token: 'demo-token-customer', user: USERS.customer };
  if (method === 'post' && seg === '/api/auth/logout') return { detail: 'Logged out' };
  if (method === 'get' && seg === '/api/auth/me') return USERS[roleFromToken()];

  // --- menu (specific before :id) ---
  if (method === 'get' && seg === '/api/menu/recommendations') return RECOMMENDATIONS;
  if (seg === '/api/menu') {
    if (method === 'get') {
      const search = (getParam(config, 'search') || '').toLowerCase();
      const cat = getParam(config, 'category') || '';
      let items = MENU.filter((i) => i.available);
      if (cat) items = items.filter((i) => i.category === cat);
      if (search) items = items.filter((i) => i.name.toLowerCase().includes(search) || (i.description || '').toLowerCase().includes(search));
      return items;
    }
    if (method === 'post') return { ...MENU[0], id: 200, ...body };
  }
  m = seg.match(/^\/api\/menu\/(\d+)$/);
  if (m) {
    if (method === 'delete') return null;
    if (method === 'patch') { const it = MENU.find((x) => x.id === Number(m[1])) || MENU[0]; return { ...it, ...body }; }
    return MENU.find((x) => x.id === Number(m[1])) || MENU[0];
  }

  // --- orders (specific before :id) ---
  if (method === 'get' && seg === '/api/orders/kitchen') return Object.values(ORDERS).filter((o) => ['pending', 'preparing'].includes(o.status)).sort((a, b) => a.created_at.localeCompare(b.created_at));
  if (method === 'get' && seg === '/api/orders/waiter') return Object.values(ORDERS).filter((o) => o.status === 'ready').sort((a, b) => a.created_at.localeCompare(b.created_at));
  if (method === 'post' && seg === '/api/orders') return placeOrder(body);
  m = seg.match(/^\/api\/orders\/(\d+)\/status$/);
  if (m && method === 'patch') {
    const o = ORDERS[m[1]];
    const status = body.status;
    if (o) { o.status = status; o.updated_at = '2026-06-17T19:50:00Z'; }
    return { id: Number(m[1]), status, updated_at: '2026-06-17T19:50:00Z' };
  }
  m = seg.match(/^\/api\/orders\/(\d+)$/);
  if (m && method === 'get') return ORDERS[m[1]] || ORDERS[1001];

  // --- tables (specific before :id) ---
  if (method === 'get' && seg === '/api/tables/my') return { table: TABLES[0] };
  if (method === 'get' && seg === '/api/tables') return TABLES;
  m = seg.match(/^\/api\/tables\/(\d+)\/assign$/);
  if (m && method === 'post') { const t = TABLES.find((x) => x.id === Number(m[1])) || TABLES[0]; t.status = 'occupied'; return t; }

  // --- billing ---
  m = seg.match(/^\/api\/billing\/invoice\/(\d+)\/pay$/);
  if (m && method === 'post') return { id: 5000 + (Number(m[1]) % 1000), status: 'paid', paid_at: '2026-06-17T19:46:00Z' };
  m = seg.match(/^\/api\/billing\/invoice\/(\d+)$/);
  if (m && method === 'get') return invoiceFor(m[1]);

  // --- manager ---
  if (method === 'get' && seg === '/api/manager/analytics') {
    const period = getParam(config, 'period') || 'day';
    return period === 'day' ? ANALYTICS_DAY : { ...ANALYTICS_WEEK, period };
  }
  if (method === 'post' && seg === '/api/manager/staff') return { id: 10, email: 'new.hire@walters.example.com', name: 'New Hire', role: body.role || 'waiter' };
  if (method === 'get' && seg === '/api/manager/invoices') return INVOICES;
  if (seg === '/api/manager/pricing') {
    if (method === 'get') return PRICING;
    if (method === 'post') return { id: 4, demand_threshold: body.demand_threshold ?? 10, multiplier: body.multiplier ?? '1.50' };
  }
  if (method === 'delete' && /^\/api\/manager\/pricing\/\d+$/.test(seg)) return null;
  if (method === 'get' && seg === '/api/manager/simulation/live') return SIM_LIVE;
  if (method === 'post' && seg === '/api/manager/simulation/start') return { detail: 'Simulation started.', task_id: '8d2f4a1c-7b3e-4c9a-9f12-0a1b2c3d4e5f', state: 'PENDING', orders: body.orders ?? 120, interval: body.interval ?? 0.15 };
  if (method === 'post' && seg === '/api/manager/simulation/stop') return { detail: 'Simulation stopped.', running: false, task_id: '8d2f4a1c-7b3e-4c9a-9f12-0a1b2c3d4e5f' };
  if (method === 'get' && seg === '/api/manager/simulation/status') return { running: false, state: 'IDLE', task_id: null };
  if (method === 'post' && seg === '/api/manager/simulation/reset') return { detail: 'Demo data reset: demo orders cleared and demo tables freed.', orders_deleted: 120, invoices_deleted: 118, tables_freed: 6 };

  return { detail: 'Not found (demo)' };
}

const ADAPTER = (config) => {
  const method = (config.method || 'get').toLowerCase();
  const rawUrl = config.url || '';
  const path = rawUrl.split('?')[0];
  const seg = path.replace(/\/+$/, '') || path; // strip trailing slash for matching
  const data = route(method, seg, config);
  const status = data === null ? 204 : 200;
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ data, status, statusText: status === 204 ? 'No Content' : 'OK', headers: {}, config, request: {} });
    }, 120);
  });
};
axios.defaults.adapter = ADAPTER;

