function sequenceFor(path) {
  // path looks like /ws/kitchen/ or /ws/orders/1006/ etc.
  if (path.startsWith('/ws/kitchen')) {
    return [{ at: 4500, msg: { type: 'new_order', order_id: 1006, table_number: 2, items: [{ name: 'Grilled Ribeye Steak', quantity: 1 }, { name: 'House Wine (Glass)', quantity: 2 }], created_at: '2026-06-17 19:42:00.123456+00:00' } }];
  }
  if (path.startsWith('/ws/waiter')) {
    return [{ at: 5000, msg: { type: 'order_ready', order_id: 1003, table_number: 4 } }];
  }
  const om = path.match(/\/ws\/orders\/(\d+)/);
  if (om) {
    const id = Number(om[1]);
    return [
      { at: 3000, msg: { type: 'order_status_update', order_id: id, status: 'preparing', updated_at: '2026-06-17T19:46:00Z' } },
      { at: 7000, msg: { type: 'order_status_update', order_id: id, status: 'ready', updated_at: '2026-06-17T19:50:00Z' } },
      { at: 11000, msg: { type: 'order_status_update', order_id: id, status: 'delivered', updated_at: '2026-06-17T19:55:00Z' } },
    ];
  }
  if (path.startsWith('/ws/simulation')) {
    return [2500, 5500, 8500, 11500].map((at) => ({ at, msg: SIM_LIVE }));
  }
  return [];
}

